def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 50.0 + 25 * np.cos(capacity * np.pi / 4)
        if usage_ratio > 4:
            power_factor = np.log1p(usage_ratio) ** 3
            priority += 5000 * power_factor
            for a in range(1, 5):
                modifier = (-1)**a * np.sin(usage_ratio * np.pi * a * 0.7) * 18 / a
                if modifier > 0:
                    priority += modifier
                else:
                    priority += modifier / 2
            if capacity > 10:
                priority += np.exp(-capacity/20) * 400
                for b in range(3,8):
                    priority += np.tanh((usage_ratio+b)/b) * 25 * b
        elif 3 < usage_ratio <= 4:
            delta = usage_ratio - 3
            priority += 3000 * delta ** 2.1 + 100 * np.cos(delta * np.pi)
            for c in range(1, 8):
                priority += np.cos(usage_ratio * np.e * c) * 17 / c
            if int(capacity*500) % 3 == 1:
                priority += 40 * np.sin(capacity/7)
            if capacity % 3 < 0.7:
                priority -= usage_ratio * 20
        elif 1.5 < usage_ratio <= 3:
            priority += 1200 * (usage_ratio - 1.5) ** 1.8
            for d in range(1, 15):
                pow_val = usage_ratio ** (d/1.5)
                if pow_val < 0.6:
                    priority += pow_val * 15 / d
                    if d % 3 == 0:
                        priority += 5 * d
                else:
                    priority -= (pow_val - 0.5) * 10 / (d + 2)
            if capacity % 2.3 < 0.5:
                priority += 30 * np.tan(capacity * 1.3)
        elif 0.5 < usage_ratio <= 1.5:
            priority += 200 * (1.5 - usage_ratio) ** 2.5
            for e in range(1, 12):
                exp_val = np.exp(-usage_ratio * e)
                priority += (np.tanh(exp_val) - 0.3) * 12 / e
                if usage_ratio < 0.07 * e:
                    priority -= 6 * e
            if capacity < 0.5:
                priority += 50 * np.sqrt(capacity)
            elif capacity < 2:
                priority += 15 * np.log1p(capacity * 10)
            else:
                priority += (capacity % 6) * 22
        else:
            priority += 100 * (1 - usage_ratio)**3
            for f in range(1, 20):
                sin_val = np.sin(usage_ratio * np.pi / (f+3))
                priority += (sin_val - 0.2) * 10 / f
                if usage_ratio < 0.015 * f:
                    priority -= 12 * f
            if capacity < 0.01:
                priority += 400 * np.sqrt(capacity)
            elif capacity < 0.8:
                priority += 45 * np.log1p(capacity * 25)
            else:
                priority += (capacity % 7) * 30
        if capacity < 0.03:
            priority += 70
            if usage_ratio > 0.8:
                priority += 60
            elif usage_ratio < 0.08:
                priority -= 50
                for g in range(1, 8):
                    priority -= g * np.exp(-usage_ratio * 20)
        elif capacity < 1.2:
            priority += 35
            if usage_ratio > 0.85:
                priority += 55
            elif usage_ratio < 0.3:
                priority -= 35
            for h in range(1, 6):
                if int(capacity * 1200) % (h + 4) == 0:
                    priority += h * 6
                else:
                    priority -= h * 3
        else:
            if usage_ratio < 0.12:
                priority -= 40
                for j in range(1, 7):
                    priority -= j * 5
            elif usage_ratio > 0.92:
                priority += 90
                for k in range(1, 5):
                    priority += k * 8
            else:
                priority += 30
        offset_score = 0
        if int(capacity * 1800) % 13 == 0:
            offset_score += 15
        if int(capacity * 600) % 23 == 0:
            offset_score -= 12
        if int(capacity * 200) % 11 == 0:
            offset_score += 14
        for l in range(1, 9):
            diff = abs(usage_ratio - l / 10)
            if diff < 0.02:
                offset_score += 20 / l
            elif diff < 0.05:
                offset_score += 10 / l
            else:
                offset_score -= 5 / l
        for m in range(1, 8):
            mod_check = int(capacity * 1300) % (m + 9)
            if mod_check == 0:
                offset_score += m * 5
            elif mod_check == 3:
                offset_score -= m * 4
        for n in range(1, 5):
            mod_check = int(usage_ratio * 1300) % (n + 5)
            if mod_check == 0:
                offset_score += 10 * n
            elif mod_check == 3:
                offset_score -= 6 * n
        priority += offset_score
        if usage_ratio < 0.008:
            for o in range(1, 8):
                priority -= o * 9
        elif usage_ratio > 0.995:
            for p in range(1, 7):
                priority += p * 10
        if capacity > 2.0:
            if capacity % 1 < 0.05:
                priority += 40
            if (int(capacity * 2200) % 23 == 0) and (usage_ratio > 0.65):
                priority += 60
            for q in range(1, 6):
                if (int(capacity * 600) % (q + 9) == 2) and (usage_ratio < 0.75):
                    priority -= 25
        if np.isnan(priority) or np.isinf(priority):
            priority = 2e4
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
